_d[11795] = {"Emergency Protocol: Section 8.2, Paragraph C",{{25807}},{{25807}},68,71,1101,nil,{"Recover 6 Fizzcrank Pilot Insignia from the bodies of Fizzcrank Recon Pilots and return them to Iggy \"Tailspin\" Cogtoggle in the Scalding Pools."},nil,{nil,nil,{{35126}}},nil,nil,{11728},nil,nil,nil,3537,nil,nil,nil,nil,11796,136,nil,nil,{{1050,250}}}
_d[11796] = {"Emergency Protocol: Section 8.2, Paragraph D",{{25807}},{{25807}},68,71,1101,nil,{"Iggy \"Tailspin\" Cogtoggle wants you to scuttle the Eastern Wreck, a Southern Wreck, and a Northwestern Wreck."},nil,{{{25847,"Scuttle the Eastern Wreck"},{25846,"Scuttle a Southern Wreck"},{25845,"Scuttle a Northwestern Wreck"}}},35224,nil,{11795},nil,nil,nil,3537,nil,nil,nil,{35224},11873,128,nil,nil,{{1050,250}}}
_d[11797] = {"The Siege",{{25816}},{{25816}},68,71,1101,nil,{"Sergeant Hammerhill wants you to kill 6 Crypt Crawlers in the Sands of Nasam outside of Valiance Keep."},nil,{{{25227}}},nil,nil,{11727},nil,nil,nil,3537,nil,nil,nil,nil,11889,136,nil,nil,{{1050,250}}}
_d[11798] = {"The Gearmaster",{{25747}},{{25590}},68,72,1101,nil,{"Research the Gearmaster's Manual and return Mechazod's Head to Fizzcrank Fullthrottle."},nil,{{{27995,"The Gearmaster's Manual researched"}},nil,{{35486}}},nil,nil,{11788},nil,nil,nil,3537,nil,nil,nil,nil,nil,136,nil,nil,{{1050,350}}}
